const payload = $json.body ?? $json;

const toCleanString = (value) => (typeof value === 'string' ? value.trim() : '');
const stripWrappingQuotes = (value) => value.replace(/^['"]|['"]$/g, '');

const getEnv = (key) => {
  if (typeof $env !== 'undefined' && $env && typeof $env[key] === 'string') {
    return stripWrappingQuotes($env[key].trim());
  }
  return '';
};

const normalizeNotionPageId = (rawValue) => {
  const value = toCleanString(rawValue);
  if (!value) return '';

  const uuidLikeMatch = value.match(/[0-9a-fA-F]{32}/);
  if (uuidLikeMatch) return uuidLikeMatch[0].toLowerCase();

  const compact = value.replace(/-/g, '');
  if (/^[0-9a-fA-F]{32}$/.test(compact)) return compact.toLowerCase();

  return value;
};

const toObject = (value) => {
  if (value && typeof value === 'object') return value;
  if (typeof value === 'string') {
    try {
      return JSON.parse(value);
    } catch {
      return { raw: value };
    }
  }
  return { raw: value };
};

const wait = (milliseconds) =>
  new Promise((resolve) => {
    setTimeout(resolve, milliseconds);
  });

const name = toCleanString(payload.name);
const email = toCleanString(payload.email).toLowerCase();
const message = toCleanString(payload.message);
const source = toCleanString(payload.source) || 'webhook';
const phone = toCleanString(payload.phone);

const errors = [];
if (name.length < 2) errors.push('name es obligatorio y debe tener minimo 2 caracteres');
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(email)) errors.push('email es obligatorio y debe tener formato valido');
if (message.length < 5) errors.push('message es obligatorio y debe tener minimo 5 caracteres');
if (phone && phone.length < 7) errors.push('phone, si llega, debe tener minimo 7 caracteres');

if (errors.length > 0) {
  return [
    {
      json: {
        success: false,
        status: 400,
        error: 'Payload invalido',
        details: errors,
      },
    },
  ];
}

if (!helpers || typeof helpers.httpRequest !== 'function') {
  return [
    {
      json: {
        success: false,
        status: 500,
        error: 'Entorno de n8n invalido',
        details: 'helpers.httpRequest no esta disponible en este nodo',
      },
    },
  ];
}

const config = {
  gsheetWebhookUrl: getEnv('GSHEET_WEBHOOK_URL'),
  resendApiKey: getEnv('RESEND_API_KEY'),
  resendFrom: getEnv('RESEND_FROM'),
  notionToken: getEnv('NOTION_TOKEN'),
  notionParentPageId: normalizeNotionPageId(getEnv('NOTION_PARENT_PAGE_ID')),
};

const missingEnv = [];
if (!config.gsheetWebhookUrl) missingEnv.push('GSHEET_WEBHOOK_URL');
if (!config.resendApiKey) missingEnv.push('RESEND_API_KEY');
if (!config.resendFrom) missingEnv.push('RESEND_FROM');
if (!config.notionToken) missingEnv.push('NOTION_TOKEN');
if (!config.notionParentPageId) missingEnv.push('NOTION_PARENT_PAGE_ID');

if (missingEnv.length > 0) {
  return [
    {
      json: {
        success: false,
        status: 500,
        error: 'Configuracion incompleta en n8n',
        details: missingEnv.map((key) => `Falta la variable ${key}`),
      },
    },
  ];
}

const contact = {
  name,
  email,
  phone: phone || null,
  message,
  source,
  receivedAt: new Date().toISOString(),
};

const integrations = {
  sheets: {
    success: false,
    attempts: 0,
    response: null,
    error: null,
  },
  email: {
    success: false,
    attempts: 0,
    response: null,
    error: null,
    retryScheduled: false,
  },
  notion: {
    success: false,
    attempts: 0,
    response: null,
    error: null,
  },
};

const warnings = [];

const escapeHtml = (value) =>
  value
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');

const postJson = async (url, headers, body) =>
  await helpers.httpRequest({
    method: 'POST',
    url,
    headers,
    body: JSON.stringify(body),
  });

const sendWithRetry = async (step, url, headers, body, retries = 0, backoffMs = 1200) => {
  let attempts = 0;
  let lastError = 'Unknown error';

  while (attempts <= retries) {
    attempts += 1;

    try {
      const rawResponse = await postJson(url, headers, body);
      return {
        ok: true,
        attempts,
        response: toObject(rawResponse),
        error: null,
      };
    } catch (error) {
      lastError = error instanceof Error ? error.message : String(error);

      if (attempts <= retries) {
        await wait(backoffMs * attempts);
      }
    }
  }

  return {
    ok: false,
    attempts,
    response: null,
    error: `${step} fallo: ${lastError}`,
  };
};

try {
  const sheetsResult = await sendWithRetry(
    'google_sheets',
    config.gsheetWebhookUrl,
    {
      'Content-Type': 'application/json',
    },
    contact,
    1,
    1000,
  );

  integrations.sheets = {
    success: sheetsResult.ok,
    attempts: sheetsResult.attempts,
    response: sheetsResult.response,
    error: sheetsResult.error,
  };

  if (!sheetsResult.ok) {
    return [
      {
        json: {
          success: false,
          status: 500,
          error: 'No se pudo guardar el contacto en Google Sheets',
          details: sheetsResult.error,
          contact,
          integrations,
          warnings,
        },
      },
    ];
  }

  if (!sheetsResult.response || sheetsResult.response.success !== true) {
    return [
      {
        json: {
          success: false,
          status: 500,
          error: 'Google Sheets no confirmo el guardado',
          details: sheetsResult.response,
          contact,
          integrations,
          warnings,
        },
      },
    ];
  }

  const emailHtml = `<p>Hola ${escapeHtml(contact.name)},</p>
<p>Recibimos tu mensaje y pronto te responderemos.</p>
<p><strong>Mensaje recibido:</strong> ${escapeHtml(contact.message)}</p>
<p>Gracias por contactarnos.</p>`;

  const emailResult = await sendWithRetry(
    'resend_email',
    'https://api.resend.com/emails',
    {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${config.resendApiKey}`,
    },
    {
      from: config.resendFrom,
      to: [contact.email],
      subject: 'Confirmacion de contacto',
      html: emailHtml,
    },
    2,
    1500,
  );

  integrations.email = {
    success: emailResult.ok,
    attempts: emailResult.attempts,
    response: emailResult.response,
    error: emailResult.error,
    retryScheduled: !emailResult.ok,
  };

  if (!emailResult.ok) {
    warnings.push(
      'No se pudo enviar el email de confirmacion despues de 3 intentos. Se creo tarea en Notion para seguimiento manual.',
    );
  }

  const notionTitle = `Contacto: ${contact.name}`.slice(0, 200);
  const notionMessage = contact.message.slice(0, 1800);

  const children = [
    {
      object: 'block',
      type: 'to_do',
      to_do: {
        rich_text: [
          {
            type: 'text',
            text: {
              content: `Responder a ${contact.name} (${contact.email})`,
            },
          },
        ],
        checked: false,
      },
    },
    {
      object: 'block',
      type: 'paragraph',
      paragraph: {
        rich_text: [
          {
            type: 'text',
            text: {
              content: `Mensaje: ${notionMessage}`,
            },
          },
        ],
      },
    },
    {
      object: 'block',
      type: 'paragraph',
      paragraph: {
        rich_text: [
          {
            type: 'text',
            text: {
              content: `Fuente: ${contact.source} | Fecha: ${contact.receivedAt}`,
            },
          },
        ],
      },
    },
  ];

  if (contact.phone) {
    children.splice(1, 0, {
      object: 'block',
      type: 'paragraph',
      paragraph: {
        rich_text: [
          {
            type: 'text',
            text: {
              content: `Telefono: ${contact.phone}`,
            },
          },
        ],
      },
    });
  }

  if (!emailResult.ok) {
    children.splice(1, 0, {
      object: 'block',
      type: 'paragraph',
      paragraph: {
        rich_text: [
          {
            type: 'text',
            text: {
              content: 'ALERTA: Email de confirmacion no enviado. Requiere seguimiento manual.',
            },
          },
        ],
      },
    });
  }

  const notionResult = await sendWithRetry(
    'notion_task',
    'https://api.notion.com/v1/pages',
    {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${config.notionToken}`,
      'Notion-Version': '2022-06-28',
    },
    {
      parent: {
        page_id: config.notionParentPageId,
      },
      properties: {
        title: {
          title: [
            {
              type: 'text',
              text: {
                content: notionTitle,
              },
            },
          ],
        },
      },
      children,
    },
    1,
    1200,
  );

  integrations.notion = {
    success: notionResult.ok,
    attempts: notionResult.attempts,
    response: notionResult.response,
    error: notionResult.error,
  };

  if (!notionResult.ok) {
    return [
      {
        json: {
          success: false,
          status: 500,
          error: 'No se pudo crear la tarea en Notion',
          details: notionResult.error,
          contact,
          integrations,
          warnings,
        },
      },
    ];
  }

  const status = emailResult.ok ? 200 : 207;
  const messageResponse = emailResult.ok
    ? 'Formulario procesado correctamente'
    : 'Formulario procesado con incidencias (email pendiente)';

  return [
    {
      json: {
        success: true,
        status,
        message: messageResponse,
        contact,
        integrations,
        warnings,
      },
    },
  ];
} catch (error) {
  return [
    {
      json: {
        success: false,
        status: 500,
        error: 'Error inesperado al ejecutar la automatizacion',
        details: error instanceof Error ? error.message : String(error),
      },
    },
  ];
}
